34	// ── Data Quality Scoring ──────────────────────────────────────
35	// Computes a 0.0–1.0 quality score for each incoming event.
36	// High-quality events get full weight in the scoring engine.
37	// Low-quality events are stored but their influence is reduced.
38	//
39	// Based on what the SDK actually sends automatically:
40	//   ALWAYS present (SDK captures automatically):
41	//     agent_id, action_name, issue_type, success, session_id, response_ms
42	//   ONLY present if developer provides score_fn:
43	//     outcome_score
44	//   NEVER sent by SDK auto-logging:
45	//     business_outcome, task_name (always inferred from issue_type)
46	//
47	// Deductions (cumulative, floored at 0.0):
48	//   -0.25  outcome_score absent     (no score_fn provided — primary signal missing)
49	//   -0.20  is_inconsistent          (success=true but score < 0.3)
50	//   -0.20  mapping_confidence < 0.7 (issue_type → task mapping is uncertain)
51	//   -0.10  business_outcome absent  (SDK never sends this — developer must add explicitly)
52	//
53	// NOT penalised (SDK always provides these):
54	//   session_id  — SDK generates UUID per call
55	//   response_ms — SDK measures latency automatically
56	//
57	// Never throws. Returns a value in [0.0, 1.0].
58	interface DataQualityInput {
59	    outcomeScoreRaw: number | null | undefined;
60	    isInconsistent: boolean;
61	    mappingConfidence: number;
62	    businessOutcome: string | null | undefined;
63	    inferenceConfidence?: number | null;
64	}
65	
66	function computeDataQuality(input: DataQualityInput): number {
67	    let score = 1.0;
68	
69	    if (input.outcomeScoreRaw === null || input.outcomeScoreRaw === undefined) {
70	        // Score was inferred — penalize by inverse of inference confidence.
71	        // High confidence inference (0.75) → penalty ~0.06
72	        // Low confidence inference (0.30)  → penalty ~0.18
73	        // No inference at all              → penalty 0.25 (original behavior)
74	        const conf = input.inferenceConfidence ?? 0;
75	        const penalty = conf > 0
76	            ? Math.max(0.05, 0.25 * (1 - conf))
77	            : 0.25;
78	        score -= penalty;
79	    }
80	    if (input.isInconsistent) {
81	        score -= 0.20;
82	    }
83	    if (input.mappingConfidence < 0.70) {
84	        score -= 0.20;
85	    }
86	    if (!input.businessOutcome) {
87	        score -= 0.10;
88	    }
89	
90	    return Number(Math.max(0.0, score).toFixed(4));
91	}
92	
93	// ── Payload size guard (64KB) ─────────────────────────────────
94	const MAX_RAW_CONTEXT_BYTES = 64 * 1024;
95	
96	const LOCAL_DEFAULT_TRUST: AgentTrustScore = {
97	    trust_score: 0.5,
98	    trust_status: 'new',
99	    consecutive_failures: 0,
100	};
101	
102	const LOCAL_DEFAULT_POLICY_CONFIG: CustomerPolicyConfig = {
103	    risk_tolerance: 'balanced',
104	    escalation_score: 0.20,
105	    exploration_rate: 0.05,
106	    min_confidence: 0.30,
107	};
108	
109	interface InconsistencyEvaluation {
110	    isInconsistent: boolean;
111	    type: string | null;
112	    reason: string | null;
113	    ruleVersion: string | null;
114	}
115	
116	interface RetryChainState {
117	    retryChainId: string | null;
118	    retryAttempt: number | null;
119	    crossEventAttemptCount: number | null;
120	    canonicalOutcomeId: string | null;
121	}
122	
123	type ExecutionStatus = 'COMPLETED' | 'FAILED';
124	type StatusOrigin = 'explicit' | 'inferred_from_success' | 'inferred_from_score' | 'reconciled_feedback';
125	
126	function clamp01(value: number): number {
127	    if (!Number.isFinite(value)) return 0;
128	    return Math.max(0, Math.min(1, value));
129	}
130	
131	function normalizeExecutionStatus(value: unknown): ExecutionStatus | null {
132	    if (typeof value !== 'string') return null;
133	    const normalized = value.trim().toUpperCase();
134	    if (normalized === 'COMPLETED') return 'COMPLETED';
135	    if (normalized === 'FAILED') return 'FAILED';
136	    return null;
137	}
138	
139	function normalizeFailureToken(value: unknown, maxLen: number): string | null {
140	    if (typeof value !== 'string') return null;
141	    const normalized = sanitizeString(value, maxLen)
142	        .trim()
143	        .toLowerCase()
144	        .replace(/\s+/g, '_')
145	        .replace(/[^a-z0-9_]/g, '_')
146	        .replace(/_+/g, '_')
147	        .replace(/^_+|_+$/g, '');
148	    if (!normalized) return null;
149	    return normalized.slice(0, maxLen);
150	}
151	
152	const FAILURE_REASON_CODE_VOCAB = new Set([
153	    'execution_failed',
154	    'timeout_error',
155	    'validation_failed',
156	    'dependency_failure',
157	    'policy_blocked',
158	    'feedback_marked_failure',
159	    'cross_event_conflict',
160	    'unknown_failure',
161	]);
162	
163	const FAILURE_STAGE_VOCAB = new Set([
164	    'action_selection',
165	    'action_execution',
166	    'ingest_validation',
167	    'verification',
168	    'delayed_feedback',
169	    'downstream_signal',
170	    'policy_gate',
171	    'unknown_stage',
172	]);
173	
174	function normalizeFailureReasonCode(value: unknown): string | null {
175	    const token = normalizeFailureToken(value, 80);
176	    if (!token) return null;
177	    return FAILURE_REASON_CODE_VOCAB.has(token)
178	        ? token
179	        : 'unknown_failure';
180	}
181	
182	function normalizeFailureStage(value: unknown): string | null {
183	    const token = normalizeFailureToken(value, 40);
184	    if (!token) return null;
185	    return FAILURE_STAGE_VOCAB.has(token)
186	        ? token
187	        : 'unknown_stage';
188	}
189	
190	function statusFromOutcomeScore(score: number | null): ExecutionStatus | null {
191	    if (score === null || !Number.isFinite(score)) return null;
192	    return score >= 0.5 ? 'COMPLETED' : 'FAILED';
193	}
194	
195	function parseOptionalNumber(value: unknown): number | null {
196	    const parsed = Number(value);
197	    if (!Number.isFinite(parsed)) return null;
198	    return parsed;
199	}
200	
201	function evaluateInconsistency(params: {
202	    finalSuccess: boolean;
203	    outcomeScoreRaw: number | null;
204	    businessOutcome: string | null | undefined;
205	    verifierDiscrepancy: boolean;
206	}): InconsistencyEvaluation {
207	    const lowThreshold = clamp01(
208	        parseOptionalNumber(process.env.LI_INCONSISTENCY_THRESHOLD) ?? 0.3,
209	    );
210	    const highThreshold = clamp01(
211	        parseOptionalNumber(process.env.LI_INCONSISTENCY_HIGH_THRESHOLD) ?? 0.7,
212	    );
213	
214	    if (params.verifierDiscrepancy) {
215	        return {
216	            isInconsistent: true,
217	            type: 'verifier_discrepancy',
218	            reason: 'Verifier signal contradicted self-reported outcome.',
219	            ruleVersion: 'v2:verifier_discrepancy',
220	        };
221	    }
222	
223	    if (
224	        params.finalSuccess === true
225	        && params.outcomeScoreRaw !== null
226	        && params.outcomeScoreRaw < lowThreshold
227	    ) {
228	        return {
229	            isInconsistent: true,
230	            type: 'success_low_score',
231	            reason: `success=true but outcome_score_raw=${params.outcomeScoreRaw.toFixed(4)} is below threshold ${lowThreshold.toFixed(4)}.`,
232	            ruleVersion: `v2:success_low_score:threshold=${lowThreshold.toFixed(4)}`,
233	        };
234	    }
235	
236	    if (
237	        params.finalSuccess === false
238	        && params.outcomeScoreRaw !== null
239	        && params.outcomeScoreRaw > highThreshold
240	    ) {
241	        return {
242	            isInconsistent: true,
243	            type: 'failure_high_score',
244	            reason: `success=false but outcome_score_raw=${params.outcomeScoreRaw.toFixed(4)} exceeds threshold ${highThreshold.toFixed(4)}.`,
245	            ruleVersion: `v2:failure_high_score:threshold=${highThreshold.toFixed(4)}`,
246	        };
247	    }
248	
249	    if (
250	        params.finalSuccess === true
251	        && (params.businessOutcome === 'partial' || params.businessOutcome === 'failed')
252	    ) {
253	        return {
254	            isInconsistent: true,
255	            type: 'success_business_conflict',
256	            reason: `success=true but business_outcome=${params.businessOutcome}.`,
257	            ruleVersion: 'v2:success_business_conflict',
258	        };
259	    }
260	
261	    return {
262	        isInconsistent: false,
263	        type: null,
264	        reason: null,
265	        ruleVersion: null,
266	    };
267	}
