611	async function resolveActionId(c: Context, body: any, customerId: string): Promise<string> {
612	    // Phase 1: Causal Graph inferred action — use inferred_action_id directly.
613	    // The Proxy interceptor already validated this by watching what the agent called.
614	    if (body.signal_source === 'causal_graph' && body.inferred_action_id && !body.action_name) {
615	        const { data: actionRow } = await supabase
616	            .from('dim_actions')
617	            .select('action_id, action_name')
618	            .eq('action_id', body.inferred_action_id)
619	            .eq('customer_id', customerId)
620	            .maybeSingle();
621	        if (actionRow) {
622	            body.action_name = actionRow.action_name;
623	            return actionRow.action_id;
624	        }
625	        // Not found — fall through to normal resolution path
626	    }
627	
628	    // Path 1: action_id provided (backward compat) — resolve to action_name
629	    if (!body.action_name && (body.action_id_input || body.action_id)) {
630	        const incomingId = body.action_id_input ?? body.action_id;
631	        const { data: actionRow } = await supabase
632	            .from('dim_actions')
633	            .select('action_id, action_name')
634	            .eq('action_id', incomingId)
635	            .eq('customer_id', customerId)
636	            .maybeSingle();
637	
638	        if (actionRow) {
639	            body.action_name = actionRow.action_name;
640	            return actionRow.action_id;
641	        }
642	        // action_id came from our own get_scores response but the action row
643	        // doesn't exist yet (cold-start: scores returned a UUID before dim_actions
644	        // was seeded). Auto-register with a stable name derived from the UUID.
645	        const derivedName = `action_${(incomingId as string).slice(0, 8)}`;
646	        body.action_name = derivedName;
647	        // Fall through to Path 3 — validateAction() will auto-register via upsert.
648	    }
649	
650	    // Path 2: action_name already resolved by middleware
651	    const validatedAction = c.get('validated_action') as any;
652	    if (validatedAction) return validatedAction.action_id;
653	
654	    // Path 3: direct validation
655	    if (!body.action_name) {
656	        throw new Error('UNKNOWN_ACTION:MISSING_FIELD:action_name or action_id is required');
657	    }
658	    const { validateAction, normalizeActionName } = await import('../middleware/validate-action.js');
659	    body.action_name = normalizeActionName(body.action_name);
660	    const result = await validateAction(body.action_name, customerId, body.action_params);
661	    if (!result.valid) throw new Error(`UNKNOWN_ACTION:${result.error_code ?? 'UNKNOWN_ACTION'}:${result.error}`);
662	    return result.action_id!;
663	}
