665	// ── FIX 2: resolveContextId now accepts and uses customerId ────
666	// BEFORE: context was looked up only by (issue_type, environment).
667	// This caused ALL customers with the same issue_type to share one
668	// context_id row, meaning Customer A's outcome scores bled into
669	// Customer B's recommendations — a complete multi-tenancy failure.
670	//
671	// AFTER: every SELECT and INSERT is scoped by customer_id.
672	// Each customer gets their own context row per (issue_type, environment).
673	// This means dim_contexts grows by (unique customers × unique issue_types)
674	// which is expected and correct — the composite unique index on
675	// (customer_id, issue_type, environment) prevents duplicates.
676	async function resolveContextId(body: any, customerId: string): Promise<string> {
677	    const { data: ctx, error } = await supabase
678	        .from('dim_contexts')
679	        .upsert(
680	            {
681	                customer_id: customerId,
682	                issue_type: body.issue_type,
683	                environment: body.environment,
684	                customer_tier: body.customer_tier ?? null,
685	            },
686	            {
687	                onConflict: 'customer_id,issue_type,environment',
688	                ignoreDuplicates: false,
689	            }
690	        )
691	        .select('context_id')
692	        .maybeSingle();
693	
694	    if (error) {
695	        console.error('[log-outcome] resolveContextId upsert error:', error.message);
696	        throw new Error(`CONTEXT_ERROR:${error.message}`);
697	    }
698	    if (!ctx?.context_id) {
699	        // Edge case: upsert returned no row — try plain SELECT as fallback
700	        const { data: existing } = await supabase
701	            .from('dim_contexts')
702	            .select('context_id')
703	            .eq('customer_id', customerId)
704	            .eq('issue_type', body.issue_type)
705	            .eq('environment', body.environment)
706	            .maybeSingle();
707	        if (existing?.context_id) return existing.context_id;
708	        throw new Error('CONTEXT_ERROR:No context_id returned after upsert');
709	    }
710	    return ctx.context_id;
711	}
