1009	
1010	        // Recent 10 outcomes success rate
1011	        const recent10 = recentOutcomes.slice(0, 10);
1012	        const recentRate = recent10.filter((o: any) => o.success).length / 10;
1013	
1014	        // Baseline: full 20-outcome rolling window
1015	        const baselineRate = recentOutcomes.filter((o: any) => o.success).length
1016	            / recentOutcomes.length;
1017	
