475	    if (mode === 'advisory') {
476	        return {
477	            valid: true,
478	            action_id: action.action_id,
479	            action_name: action.action_name,
480	            action_category: action.action_category,
481	            required_params: action.required_params,
482	            warnings: missing.map(k => `param '${k}' is recommended but not provided`),
483	        };
484	    }
485	
486	    // disabled logic
