/**
 * Layerinfinite — middleware/validate-action.ts
 * ══════════════════════════════════════════════════════════════
 * Hallucination Prevention Middleware for Hono.
 *
 * Validates that action_name from request body exists in
 * dim_actions registry. Blocks unregistered actions with 400.
 * Uses 30-min in-memory cache to minimise DB round-trips.
 *
 * On success: sets action + validated_action on context + calls next()
 * On failure: returns 400 UNKNOWN_ACTION (not 422 per PRD)
 * ══════════════════════════════════════════════════════════════
 */

import { Context, Next } from 'hono';
import { supabase } from '../lib/supabase.js';
import crypto from 'node:crypto';

// ── Category-based baseline priors ─────────────────────────
// Returns a starting avg_success_rate based on action_category.
function getBaselinePrior(actionCategory: string): number {
    const priors: Record<string, number> = {
        recovery: 0.70,
        escalation: 0.45,
        automation: 0.60,
        'auto-discovered': 0.55,
        custom: 0.55,
    };
    return priors[actionCategory] ?? 0.50;
}

// Fire-and-forget: seed institutional knowledge for a newly registered action.
// Uses INSERT protected by unique constraint so re-registration never overwrites
// real accumulated data. Never blocks action registration — errors are only logged.
async function seedInstitutionalKnowledge(
    actionId: string,
    actionCategory: string,
    contextType: string | null,
): Promise<void> {
    const baseline = getBaselinePrior(actionCategory);
    const contextSeed = contextType ?? 'global';
    try {
        const { error } = await supabase
            .from('dim_institutional_knowledge')
            .insert({
                pattern_id: crypto.randomUUID(),
                action_id: actionId,
                context_type: contextSeed,
                avg_success_rate: baseline,
                sample_count: 10,
            });
        // 23505 = unique_violation (row already exists) — correct, ignore silently
        if (error && error.code !== '23505') {
            console.warn('[validate-action] Knowledge seed failed (non-fatal):', {
                action_id: actionId, context_type: contextSeed, error: error.message,
            });
        }
    } catch (err: any) {
        console.warn('[validate-action] Knowledge seed exception (non-fatal):', {
            action_id: actionId, context_type: contextSeed, error: err.message,
        });
    }
}

const ACTION_CACHE_TTL_MS = 30 * 60 * 1000;  // 30 min

interface ActionCacheEntry {
    action_id: string;
    action_name: string;
    action_category: string;
    required_params: Record<string, unknown>;
    validation_mode: string;
    is_active: boolean;
    expires_at: number;
}

// Cache by customer_id:action_name
const actionCache = new Map<string, ActionCacheEntry>();

function getActionCacheKey(customerId: string, actionName: string): string {
    return `${customerId}:${actionName}`;
}

/**
 * Strip trailing version/noise suffixes from a snake_case action name.
 * Applied iteratively until stable. Minimum 3 chars preserved.
 *
 * Patterns (trailing only, never mid-string):
 *   _v2, _v1_3          → version numbers
 *   _final, _new, _old  → intent noise
 *   _test, _prod, _dev  → environment noise
 *   _handler, _fn, _impl → code noise
 */
function stripVersionSuffixes(name: string): string {
    let result = name;
    let prev = '';
    while (prev !== result && result.length > 3) {
        prev = result;
        result = result
            .replace(/_v\d+(_\d+)?$/, '')
            .replace(/_(final|new|old|temp|bak|copy)$/, '')
            .replace(/_(test|prod|dev|staging)$/, '')
            .replace(/_(handler|fn|func|impl|helper)$/, '')
            .replace(/_+$/g, '');
    }
    return result || name;
}

export function normalizeActionName(raw: string): string {
    const base = raw
        .trim()
        // camelCase / PascalCase → snake_case  (e.g. retryWith → retry_With → retry_with)
        .replace(/([a-z0-9])([A-Z])/g, '$1_$2')
        // Replace hyphens and spaces with underscores
        .replace(/[-\s]+/g, '_')
        // Collapse consecutive underscores
        .replace(/_+/g, '_')
        // Lowercase everything
        .toLowerCase()
        // Strip leading/trailing underscores
        .replace(/^_+|_+$/g, '');
    // Strip trailing version/noise suffixes AFTER camelCase split + lowercase.
    // Order matters: retryPaymentV2 → retry_payment_v2 → retry_payment
    return stripVersionSuffixes(base);
}

/**
 * Fire-and-forget: record an action name alias in dim_action_aliases.
 * Used when normalization maps a developer-sent raw name to a different canonical form.
 * Never blocks the hot path — errors are only logged.
 */
async function recordActionAlias(
    rawName: string,
    canonicalName: string,
    customerId: string,
    mergeReason: string,
): Promise<void> {
    if (rawName === canonicalName) return;
    try {
        const { error } = await supabase
            .from('dim_action_aliases')
            .upsert({
                raw_name: rawName,
                canonical_name: canonicalName,
                customer_id: customerId,
                merge_reason: mergeReason,
                merge_confidence: 1.000,
                similarity: null,
            }, {
                onConflict: 'raw_name,customer_id',
                ignoreDuplicates: true,
            });
        // 23505 = unique_violation (row already exists) — correct, ignore silently
        if (error && error.code !== '23505') {
            console.warn('[validate-action] Alias record failed (non-fatal):', {
                raw_name: rawName, canonical_name: canonicalName, error: error.message,
            });
        }
    } catch (err: any) {
        console.warn('[validate-action] Alias record exception (non-fatal):', err.message);
    }
}

// Evict expired entries every 5 minutes
const CLEANUP_INTERVAL_MS = 5 * 60_000;
setInterval(() => {
    const now = Date.now();
    let evicted = 0;
    for (const [key, entry] of actionCache.entries()) {
        if (entry.expires_at < now) {
            actionCache.delete(key);
            evicted++;
        }
    }
    if (evicted > 0) {
        console.info(`[cache-cleanup] Evicted ${evicted} expired entries from actionCache`);
    }
}, CLEANUP_INTERVAL_MS).unref();

setInterval(() => {
    console.info(`[cache-size] actionCache: ${actionCache.size} entries`);
}, 15 * 60_000).unref();

export interface ActionValidationResult {
    valid: boolean;
    action_id?: string;
    action_name?: string;
    action_category?: string;
    required_params?: Record<string, unknown>;
    validation_mode?: string;
    error?: string;
    error_code?: string;
    warnings?: string[];
}

// Extend Hono Context to recognize validated_action
declare module 'hono' {
    interface ContextVariableMap {
        action: {
            action_id: string;
            action_name: string;
            is_active: boolean;
        };
        validated_action: {
            action_id: string;
            action_name: string;
            action_category: string;
            validation_warnings?: string[];
        };
        parsed_body: unknown;
    }
}

// ── Middleware form ───────────────────────────────────────────
/**
 * Hono middleware that validates action_name in the request body
 * against dim_actions. Sets c.set('validated_action', ...) on success.
 */
export async function validateActionMiddleware(c: Context, next: Next): Promise<Response | void> {
    // Clone the request body so downstream handlers can read it
    let body: Record<string, unknown>;
    try {
        body = await c.req.json();
    } catch {
        return c.json({ error: 'Invalid JSON body', code: 'PARSE_ERROR' }, 400);
    }

    const rawActionName = body.action_name ?? body.actionName;
    const actionName = rawActionName && typeof rawActionName === 'string'
        ? normalizeActionName(rawActionName)
        : rawActionName;
    // Write the normalized name back so downstream handlers see the canonical form
    if (actionName && typeof actionName === 'string') {
        body.action_name = actionName;
    }
    const customerId = ((c as any).get('customerId') ?? c.get('customer_id')) as string | undefined;

    // Record alias when normalization changed the name (fire-and-forget)
    // Must be after customerId is resolved.
    if (actionName && typeof actionName === 'string' && customerId) {
        const rawLower = String(rawActionName).trim().toLowerCase()
            .replace(/[-\s]+/g, '_').replace(/_+/g, '_').replace(/^_+|_+$/g, '');
        if (rawLower !== actionName) {
            const reason = rawLower.match(/_v\d|_(final|new|old|temp|test|prod|dev|handler|fn|func|impl)$/)
                ? 'version_strip'
                : 'camel_normalize';
            void recordActionAlias(rawLower, actionName, customerId, reason);
        }
    }

    // If action_name is absent but action_id is present,
    // skip middleware validation — resolveActionId() handles it.
    if (!actionName || typeof actionName !== 'string') {
        if (body.action_id || body.action_id_input) {
            c.set('parsed_body', body);
            await next();
            return;
        }
        return c.json({ error: 'action_name or action_id is required', code: 'MISSING_FIELD' }, 400);
    }

    if (!customerId) {
        return c.json({ error: 'customerId is required', code: 'MISSING_CUSTOMER' }, 401);
    }

    // ── Cache check (fast path — skip DB on hit) ─────────────────
    // actionName is already normalized above — no further trim needed
    const cacheKey = getActionCacheKey(customerId, actionName);
    const cachedEntry = actionCache.get(cacheKey);

    if (cachedEntry && cachedEntry.expires_at > Date.now()) {
        if (!cachedEntry.is_active) {
            return c.json(
                { error: 'Action is disabled', action_name: actionName, code: 'ACTION_DISABLED' },
                403
            );
        }
        c.set('action', {
            action_id: cachedEntry.action_id,
            action_name: cachedEntry.action_name,
            is_active: cachedEntry.is_active,
        });
        c.set('validated_action', {
            action_id: cachedEntry.action_id,
            action_name: cachedEntry.action_name,
            action_category: cachedEntry.action_category,
            validation_warnings: [],
        });
        c.set('parsed_body', body);
        await next();
        return;
    }

    // ── Cache miss: look up action scoped to this customer ────────
    const { data: existingAction } = await supabase
        .from('dim_actions')
        .select('action_id, action_name, action_category, required_params, validation_mode, is_active')
        .eq('action_name', actionName)
        .eq('customer_id', customerId)
        .maybeSingle();

    if (existingAction) {
        // Write to cache so subsequent requests skip DB
        actionCache.set(cacheKey, {
            ...existingAction,
            required_params: existingAction.required_params as Record<string, unknown>,
            expires_at: Date.now() + ACTION_CACHE_TTL_MS,
        });

        if (!existingAction.is_active) {
            return c.json(
                { error: 'Action is disabled', action_name: actionName, code: 'ACTION_DISABLED' },
                403
            );
        }

        c.set('action', {
            action_id: existingAction.action_id,
            action_name: existingAction.action_name,
            is_active: existingAction.is_active,
        });
        c.set('validated_action', {
            action_id: existingAction.action_id,
            action_name: existingAction.action_name,
            action_category: existingAction.action_category,
            validation_warnings: [],
        });
        c.set('parsed_body', body);
        await next();
        return;
    }

    // ── Action not found: AUTO-REGISTER on first use ──────────────
    // AUTO-REGISTER: silently create on first use
    // This means users never need to manually register actions
    const { data: newAction, error: insertError } = await supabase
        .from('dim_actions')
        .upsert({
            action_name: actionName,
            customer_id: customerId,
            is_active: true,
            action_category: 'auto-discovered',
            action_description: 'Auto-registered on first use by SDK',
            required_params: {},
            validation_mode: 'advisory',
        }, {
            onConflict: 'action_name,customer_id',
            ignoreDuplicates: false,
        })
        .select('action_id, action_name, is_active')
        .maybeSingle();

    if (insertError || !newAction) {
        // Only fail if DB itself errors
        console.error('[validate-action] Auto-register failed', {
            action_name: actionName,
            customer_id: customerId,
            error_code: insertError?.code,
            error_message: insertError?.message,
        });
        return c.json({ error: 'Failed to register action' }, 500);
    }

    // Seed institutional knowledge for this new action.
    // issue_type from body determines which context gets the prior.
    // void — fire-and-forget, never blocks registration.
    void seedInstitutionalKnowledge(
        newAction.action_id,
        'auto-discovered',
        (body.issue_type as string | undefined) ?? null,
    );

    c.set('action', newAction);
    c.set('validated_action', {
        action_id: newAction.action_id,
        action_name: newAction.action_name,
        action_category: 'auto-discovered',
        validation_warnings: [],
    });

    // Cache the newly registered action
    actionCache.set(cacheKey, {
        action_id: newAction.action_id,
        action_name: newAction.action_name,
        action_category: 'auto-discovered',
        required_params: {},
        validation_mode: 'advisory',
        is_active: true,
        expires_at: Date.now() + ACTION_CACHE_TTL_MS,
    });

    c.set('parsed_body', body);
    await next();
}

// ── Core validation function (also exported for direct use) ──
export async function validateAction(
    actionName: string,
    customerId: string,
    params?: Record<string, unknown>
): Promise<ActionValidationResult> {
    actionName = normalizeActionName(actionName);
    const cacheKey = getActionCacheKey(customerId, actionName);
    const cached = actionCache.get(cacheKey);

    if (cached && cached.expires_at > Date.now()) {
        if (!cached.is_active) {
            return { valid: false, error: `Action "${actionName}" is disabled`, error_code: 'ACTION_DISABLED' };
        }
        return validateParams(cached, params);
    }

    // Cache miss — lookup in dim_actions
    const { data, error } = await supabase
        .from('dim_actions')
        .select('action_id, action_name, action_category, action_description, required_params, is_active, validation_mode')
        .eq('action_name', actionName)
        .eq('customer_id', customerId)
        .maybeSingle();

    if (error) {
        return { valid: false, error: `Action lookup failed: ${error.message}`, error_code: 'DB_ERROR' };
    }

    if (!data) {
        return {
            valid: false,
            error: `action_name '${actionName}' not found in registry and could not be auto-registered.`,
            error_code: 'UNKNOWN_ACTION',
        };
    }

    // Cache result
    actionCache.set(cacheKey, {
        ...data,
        required_params: data.required_params as Record<string, unknown>,
        expires_at: Date.now() + ACTION_CACHE_TTL_MS,
    });

    if (!data.is_active) {
        return { valid: false, error: `Action "${actionName}" is currently disabled`, error_code: 'ACTION_DISABLED' };
    }

    return validateParams(data, params);
}

function validateParams(
    action: { action_id: string; action_name: string; action_category: string; required_params: Record<string, unknown>, validation_mode?: string },
    params?: Record<string, unknown>
): ActionValidationResult {
    const mode = action.validation_mode ?? 'advisory';
    const required = action.required_params ?? {};
    const requiredKeys = Object.keys(required);

    const missing = requiredKeys.filter(k => !(k in (params ?? {})));

    if (missing.length === 0) {
        return {
            valid: true,
            action_id: action.action_id,
            action_name: action.action_name,
            action_category: action.action_category,
            required_params: action.required_params,
        };
    }

    if (mode === 'strict') {
        return {
            valid: false,
            error: `action '${action.action_name}' requires: ${missing.join(', ')}`,
            error_code: 'MISSING_PARAMS',
        };
    }

    if (mode === 'advisory') {
        return {
            valid: true,
            action_id: action.action_id,
            action_name: action.action_name,
            action_category: action.action_category,
            required_params: action.required_params,
            warnings: missing.map(k => `param '${k}' is recommended but not provided`),
        };
    }

    // disabled logic
    return {
        valid: true,
        action_id: action.action_id,
        action_name: action.action_name,
        action_category: action.action_category,
        required_params: action.required_params,
    };
}

// Invalidate action cache (call after admin registers new action)
export function invalidateActionCache(actionName?: string): void {
    if (actionName) {
        const normalized = normalizeActionName(actionName);
        for (const key of actionCache.keys()) {
            if (key.endsWith(`:${normalized}`)) {
                actionCache.delete(key);
            }
        }
    } else {
        actionCache.clear();
    }
}

