172	export function getOutcomeQueueMode(): QueueMode {
173	    const explicit = (process.env.LI_OUTCOME_QUEUE_MODE ?? '').trim().toLowerCase();
174	    if (explicit === 'sync') return 'sync';
175	    if (explicit === 'postgres') return 'postgres';
176	    // Default to postgres — durable queue with FOR UPDATE SKIP LOCKED, exponential
177	    // backoff, dead-letter, and stale-lock recovery. Set LI_OUTCOME_QUEUE_MODE=sync
178	    // to revert to the legacy synchronous path.
179	    return 'postgres';
180	}
